def possibleStrings(n, r, b, g):
    fact = [1] * (n + 1)
    for i in range(1, n + 1):
        fact[i] = fact[i - 1] * i
    left = n - (r + g + b)
    sum = 0
    for i in range(left + 1):
        for j in range(left - i + 1):
            k = left - (i + j)
            sum += fact[n] // (fact[i + r] * fact[j + b] * fact[k + g])
    return sum

