    for i in range(n):
        P[i][i] = True
    for i in range(n-1):
        if s[i] == s[i+1]:
            P[i][i+1] = True
            dp[i][i+1] = 1
    for gap in range(2, n):
        for i in range(n - gap):
            j = gap + i
            if s[i] == s[j] and P[i+1][j-1]:
                P[i][j] = True
            if P[i][j]:
