def kthLargestSum(arr, n, k):
    sum_arr = [0] * (n + 1)
    sum_arr[1] = arr[0]
    for i in range(2, n + 1):
        sum_arr[i] = sum_arr[i - 1] + arr[i - 1]
    Q = []
    for i in range(1, n + 1):
        for j in range(i, n + 1):
            x = sum_arr[j] - sum_arr[i - 1]
            if len(Q) < k:
                heapq.heappush(Q, x)
            else:
                if Q[0] < x:
                    heapq.heappop(Q)
                    heapq.heappush(Q, x)
    return Q[0]

