def lengthOfLongestAP(set, n):
    if n <= 2:
        return n
    L = [[0 for _ in range(n)] for _ in range(n)]
    llap = 2
    for i in range(n):
        L[i][n - 1] = 2
    for j in range(n - 2, 0, -1):
        i = j - 1
        k = j + 1
        while i >= 0 and k <= n - 1:
            if set[i] + set[k] < 2 * set[j]:
                k += 1
            elif set[i] + set[k] > 2 * set[j]:
                L[i][j] = 2
                i -= 1
            else:
                L[i][j] = L[j][k] + 1
                llap = max(llap, L[i][j])
                i -= 1
                k += 1
        while i >= 0:
            L[i][j] = 2
            i -= 1
    return llap

