    curr_rem = 0
    max_sum = 0
    sum_arr[0] = arr[0]
    for i in range(1, n):
        sum_arr[i] = sum_arr[i - 1] + arr[i]
    for i in range(n):
        curr_rem = sum_arr[i] % k
        if curr_rem == 0:
            if max_sum < sum_arr[i]:
                max_sum = sum_arr[i]
