        if cost[i] != -1:
            val.append(cost[i])
            wt.append(i + 1)
            size += 1
    n = size
    min_cost = [[0 for _ in range(W + 1)] for _ in range(n + 1)]
    for i in range(W + 1):
        min_cost[0][i] = float('inf')
