def getMinSquares(n):
    if n <= 3:
        return n
    dp = [0] * (n + 1)
    dp[0] = 0
    dp[1] = 1
    dp[2] = 2
    dp[3] = 3
    for i in range(4, n + 1):
        dp[i] = i
        for x in range(1, int(i ** 0.5) + 1):
            temp = x * x
            if temp > i:
                break
            else:
                dp[i] = min(dp[i], 1 + dp[i - temp])
    res = dp[n]
    return res

