    if n != 10:
        return False
    sum = 0
    for i in range(9):
        digit = int(isbn[i])
        if digit < 0 or digit > 9:
            return False
        sum += (digit * (10 - i))
    last = isbn[9]
    if last != 'X' and (not last.isdigit()):
        return False
    sum += (10 if last == 'X' else int(last))
    return sum % 11 == 0

