def KnapSack(val, wt, n, W):
    mat = [[0] * (W + 1), [0] * (W + 1)]
    i = 0
    while i < n:
        j = 0
        if i % 2 != 0:
            while j < W:
                j += 1
                if wt[i] <= j and j - wt[i] < W:
                    mat[1][j] = max(val[i] + mat[0][j - wt[i]], mat[0][j])
                else:
                    mat[1][j] = mat[0][j]
        else:
            while j < W:
                j += 1
                if wt[i] <= j and j - wt[i] < W:
                    mat[0][j] = max(val[i] + mat[1][j - wt[i]], mat[1][j])
                else:
                    mat[0][j] = mat[1][j]
        i += 1
    return mat[0][W] if n % 2 != 0 else mat[1][W]

