def binomialCoeffSum(n):
    C = [[0] * (n + 1) for _ in range(n + 1)]
    for i in range(n + 1):
        for j in range(min(i, n) + 1):
            if j == 0 or j == i:
                C[i][j] = 1
            else:
                C[i][j] = C[i - 1][j - 1] + C[i - 1][j]
    sum = 0
    for i in range(n + 1):
        sum += C[n][i]
    return sum

